css:
.loader {color: var(--loader-color, #e11d48);
  --loader-secondary-color: #fb7185;
  --loader-bg: #ffffff;
   display: inline-flex;
   gap: 10px;
}
.loader:before, .loader:after  {
  content: "";
   height: 20px;
   aspect-ratio: 1;
   border-radius: 50%;
   background: radial-gradient(farthest-side,currentColor 95%,#0000) 35% 35%/6px 6px no-repeat currentColor;
   transform: scaleX(var(--s,1)) rotate(0deg);
   animation: l6 1s infinite linear;
}
.loader:after  {
  --s: -1;
   animation-delay:-0.1s;
}
@keyframes l6  {
  100% {transform:scaleX(var(--s,1)) rotate(360deg);
}
}
